import { Component } from '@angular/core';

@Component({
  selector: 'app-home',
  templateUrl: './home.component.html'
})
export class HomeComponent {}
<section class="page">
  <h1>Inventory Management System (Angular)</h1>
  <p>
    This application manages item records in-browser during the current session. It supports adding,
    editing, updating, deleting, searching, and filtering inventory without any server-side interaction.
  </p>
  <p>
    Use <strong>Manage Items</strong> to maintain records and <strong>Search</strong> to filter and review all or popular items.
  </p>
</section>
